{"parts":[{"tool_name":"read_file","content":["import { useState, useEffect } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Progress } from '@/components/ui/progress';
import { Badge } from '@/components/ui/badge';
import { Loader2, RefreshCw, Sparkles, AlertCircle, CheckCircle2, AlertTriangle, Target } from 'lucide-react';
import { BudgetPlannerModal } from './BudgetPlannerModal';
import { toast } from 'sonner';
import { getBudgetQuote, getArtetaQuote } from '../lib/arteta-quotes';

interface BudgetComparison {
  category: string;
  budgeted: number;
  actual: number;
  remaining: number;
  percentUsed: number;
  status: 'under' | 'near' | 'over';
}

interface BudgetSummary {
  totalBudgeted: number;
  totalSpent: number;
  remaining: number;
  percentUsed: number;
  categoriesOverBudget: number;
  categoriesNearBudget: number;
}

interface BudgetData {
  hasBudget: boolean;
  comparison: BudgetComparison[];
  summary?: BudgetSummary;
  message?: string;
}

interface GeneratedBudget {
  budgets: Array<{
    category: string;
    monthlyBudget: number;
    avgSpend: number;
    outlierCount: number;
    confidence: 'high' | 'medium' | 'low';
  }>;
  totalMonthlyBudget: number;
  analysisDetails: {
    totalTransactions: number;
    totalOutliersRemoved: number;
    dateRange: { start: string; end: string };
    daysAnalyzed: number;
  };
}

export function BudgetView() {
  const [budgetData, setBudgetData] = useState<BudgetData | null>(null);
  const [loading, setLoading] = useState(true);
  const [generating, setGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [generationResult, setGenerationResult] = useState<GeneratedBudget | null>(null);
  const [plannerOpen, setPlannerOpen] = useState(false);

  const fetchBudget = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await fetch('/api/budget/current');
      if (!response.ok) throw new Error('Failed to fetch budget');
      const data = await response.json();
      setBudgetData(data);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load budget');
    } finally {
      setLoading(false);
    }
  };

  const generateBudget = async () => {
    setGenerating(true);
    setError(null);
    setGenerationResult(null);
    try {
      const response = await fetch('/api/budget/generate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ save: true })
      });
      if (!response.ok) {
        const err = await response.json();
        throw new Error(err.error || 'Failed to generate budget');
      }
      const data = await response.json();
      setGenerationResult(data);
      await fetchBudget();
      toast.success("Budget Generated! 🏆", {
        description: getArtetaQuote('goal_scored'),
      });
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to generate budget');
    } finally {
      setGenerating(false);
    }
  };

  useEffect(() => {
    fetchBudget();
  }, []);

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 0,
      maximumFractionDigits: 0
    }).format(amount);
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'over': return 'bg-[#EF0107]'; // Arsenal red for over budget
      case 'near': return 'bg-[#9C824A]'; // Arsenal gold for near limit
      default: return 'bg-[#063672]'; // Arsenal navy for under budget (win!)
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'over': return <AlertCircle className="h-4 w-4 text-[#EF0107]" />;
      case 'near': return <AlertTriangle className="h-4 w-4 text-[#9C824A]" />;
      default: return <CheckCircle2 className="h-4 w-4 text-[#063672]" />;
    }
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'over': return { text: 'L', color: 'bg-[#EF0107] text-white' }; // Loss
      case 'near': return { text: 'D', color: 'bg-[#9C824A] text-white' }; // Draw
      default: return { text: 'W', color: 'bg-[#063672] text-white' }; // Win
    }
  };

  const getConfidenceBadge = (confidence: string) => {
    const colors = {
      high: 'bg-[#063672]/20 text-[#4d7ec2]',
      medium: 'bg-[#9C824A]/20 text-[#c9a962]',
      low: 'bg-[#EF0107]/20 text-[#ff4d52]'
    };
    return colors[confidence as keyof typeof colors] || colors.medium;
  };

  if (loading) {
    return (
      <Card>
        <CardContent className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header with Actions */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold tracking-tight">Monthly Budget</h2>
          <p className="text-muted-foreground">
            Track your spending against AI-generated targets ⚽
          </p>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={fetchBudget} disabled={loading} className="border-[#9C824A]/30 hover:border-[#9C824A] hover:bg-[#9C824A]/10">
            <RefreshCw className="h-4 w-4 mr-2" />
            Refresh
          </Button>
          <Button 
            variant="outline" 
            size="sm"
            onClick={() => setPlannerOpen(true)}
            className="border-[#063672]/30 hover:border-[#063672] hover:bg-[#063672]/10"
          >
            <Target className="h-4 w-4 mr-2" />
            Plan My Savings
          </Button>
          <Button onClick={generateBudget} disabled={generating} className="bg-[#EF0107] hover:bg-[#b30006] text-white">
            {generating ? (
              <Loader2 className="h-4 w-4 mr-2 animate-spin" />
            ) : (
              <Sparkles className="h-4 w-4 mr-2" />
            )}
            {budgetData?.hasBudget ? 'Regenerate Budget' : 'Generate Budget'}
          </Button>
        </div>
      </div>

      {error && (
        <Card className="border-[#EF0107]/50 bg-[#EF0107]/10">
          <CardContent className="py-4">
            <div className="flex items-center gap-2 text-[#EF0107]">
              <AlertCircle className="h-5 w-5" />
              <span>{error}</span>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Generation Result */}
      {generationResult && (
        <Card className="border-[#9C824A]/50 bg-[#9C824A]/10">
          <CardHeader className="pb-2">
            <CardTitle className="text-lg text-[#9C824A]">🏆 Budget Generated!</CardTitle>
            <CardDescription className="text-[#c9a962]">
              Analyzed {generationResult.analysisDetails.totalTransactions} transactions 
              over {generationResult.analysisDetails.daysAnalyzed} days
              {generationResult.analysisDetails.totalOutliersRemoved > 0 && (
                <span> • Removed {generationResult.analysisDetails.totalOutliersRemoved} outliers</span>
              )}
            </CardDescription>
          </CardHeader>
          <CardContent>
            <p className="text-[#9C824A] font-medium">
              Total monthly budget: {formatCurrency(generationResult.totalMonthlyBudget)}
            </p>
          </CardContent>
        </Card>
      )}

      {/* No Budget State */}
      {!budgetData?.hasBudget && !generationResult && (
        <Card className="border-[#EF0107]/20 card-hover">
          <CardContent className="py-12 text-center">
            <div className="text-5xl mb-4 animate-bounce-subtle">⚽</div>
            <h3 className="text-lg font-medium mb-2">No Budget Set</h3>
            <p className="text-muted-foreground mb-2">
              Generate an AI-powered budget based on your spending history.
              We'll analyze the last 90 days and create realistic targets.
            </p>
            <p className="text-zinc-500 text-sm italic mb-4">
              "{getArtetaQuote('welcome')}"
            </p>
            <Button onClick={generateBudget} disabled={generating} className="bg-[#EF0107] hover:bg-[#b30006] text-white">
              {generating ? (
                <Loader2 className="h-4 w-4 mr-2 animate-spin" />
              ) : (
                <Sparkles className="h-4 w-4 mr-2" />
              )}
              Generate My Budget
            </Button>
          </CardContent>
        </Card>
      )}

      {/* Budget Summary */}
      {budgetData?.hasBudget && budgetData.summary && (
        <div className="grid gap-4 md:grid-cols-4">
          <Card className="border-[#EF0107]/20 hover:border-[#EF0107]/40 transition card-hover">
            <CardHeader className="pb-2">
              <CardDescription>Monthly Budget</CardDescription>
              <CardTitle className="text-2xl">
                {formatCurrency(budgetData.summary.totalBudgeted)}
              </CardTitle>
            </CardHeader>
          </Card>
          <Card className="border-[#9C824A]/20 hover:border-[#9C824A]/40 transition card-hover">
            <CardHeader className="pb-2">
              <CardDescription>Spent So Far</CardDescription>
              <CardTitle className="text-2xl">
                {formatCurrency(budgetData.summary.totalSpent)}
              </CardTitle>
            </CardHeader>
          </Card>
          <Card className="border-[#063672]/20 hover:border-[#063672]/40 transition card-hover">
            <CardHeader className="pb-2">
              <CardDescription>Remaining</CardDescription>
              <CardTitle className={`text-2xl ${budgetData.summary.remaining < 0 ? 'text-[#EF0107]' : 'text-[#9C824A]'}`}>
                {formatCurrency(budgetData.summary.remaining)}
              </CardTitle>
            </CardHeader>
          </Card>
          <Card className="border-[#EF0107]/20 hover:border-[#EF0107]/40 transition card-hover">
            <CardHeader className="pb-2">
              <CardDescription>Used</CardDescription>
              <CardTitle className="text-2xl">
                {budgetData.summary.percentUsed}%
              </CardTitle>
            </CardHeader>
            <CardContent className="pb-4">
              <Progress 
                value={Math.min(budgetData.summary.percentUsed, 100)} 
                className="h-2 [&>div]:bg-[#EF0107]"
              />
            </CardContent>
          </Card>
        </div>
      )}

      {/* Status Summary - Match Results Style */}
      {budgetData?.hasBudget && budgetData.summary && (
        <div className="flex gap-4">
          {budgetData.summary.categoriesOverBudget > 0 && (
            <Badge className="text-sm bg-[#EF0107] text-white hover:bg-[#b30006]">
              <AlertCircle className="h-3 w-3 mr-1" />
              {budgetData.summary.categoriesOverBudget} over budget (L)
            </Badge>
          )}
          {budgetData.summary.categoriesNearBudget > 0 && (
            <Badge className="text-sm bg-[#9C824A] text-white hover:bg-[#7a6639]">
              <AlertTriangle className="h-3 w-3 mr-1" />
              {budgetData.summary.categoriesNearBudget} near limit (D)
            </Badge>
          )}
        </div>
      )}

      {/* Category Breakdown */}
      {budgetData?.hasBudget && budgetData.comparison.length > 0 && (
        <Card className="border-[#EF0107]/10 card-hover">
          <CardHeader>
            <CardTitle>Category Breakdown</CardTitle>
            <CardDescription>
              Your spending by category this month — W/D/L record
            </CardDescription>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              {budgetData.comparison.map((item) => {
                const badge = getStatusBadge(item.status);
                return (
                  <div key={item.category} className="space-y-2">
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-2">
                        <span className={`w-6 h-6 rounded flex items-center justify-center text-xs font-bold ${badge.color}`}>
                          {badge.text}
                        </span>
                        <span className="font-medium">{item.category}</span>
                      </div>
                      <div className="text-right">
                        <span className={item.status === 'over' ? 'text-[#EF0107] font-medium' : ''}>
                          {formatCurrency(item.actual)}
                        </span>
                        <span className="text-muted-foreground"> / {formatCurrency(item.budgeted)}</span>
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      <Progress 
                        value={Math.min(item.percentUsed, 100)} 
                        className={`h-2 flex-1 ${item.status === 'over' ? '[&>div]:bg-[#EF0107]' : item.status === 'near' ? '[&>div]:bg-[#9C824A]' : '[&>div]:bg-[#063672]'}`}
                      />
                      <span className="text-xs text-muted-foreground w-12 text-right">
                        {item.percentUsed}%
                      </span>
                    </div>
                    {item.status === 'over' && (
                      <p className="text-xs text-[#EF0107]">
                        ❌ Over by {formatCurrency(Math.abs(item.remaining))}
                      </p>
                    )}
                  </div>
                );
              })}
            </div>
            {/* Budget summary quote */}
            {budgetData.summary && (
              <p className="text-center text-zinc-500 text-xs italic mt-6 pt-4 border-t border-zinc-800">
                "{getBudgetQuote(budgetData.summary.percentUsed)}"
              </p>
            )}
          </CardContent>
        </Card>
      )}

      {/* Budget Planner Modal */}
      <BudgetPlannerModal 
        open={plannerOpen} 
        onOpenChange={setPlannerOpen} 
        onPlanAccepted={() => {
          setGenerationResult(null);
          fetchBudget();
        }}
      />
    </div>
  );
}
