import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer
} from 'recharts';
import { SkeletonNetWorth } from './ui/skeleton';
import { getNetWorthQuote } from '../lib/arteta-quotes';

interface NetWorthBreakdown {
  assets: {
    cash: number;
    investments: number;
    total: number;
  };
  liabilities: {
    creditCards: number;
    loans: number;
    total: number;
  };
  netWorth: number;
  asOfDate: string;
}

interface HistorySnapshot {
  snapshot_date: string;
  net_worth: number;
  total_assets: number;
  total_liabilities: number;
}

interface NetWorthCardProps {
  userId?: string;
  onRefresh?: () => void;
}

// Demo data for realistic presentation
const DEMO_BREAKDOWN: NetWorthBreakdown = {
  assets: {
    cash: 12847.32,
    investments: 45230.00,
    total: 58077.32,
  },
  liabilities: {
    creditCards: 2341.89,
    loans: 8500.00,
    total: 10841.89,
  },
  netWorth: 47235.43,
  asOfDate: new Date().toISOString().split('T')[0],
};

const generateDemoHistory = (): HistorySnapshot[] => {
  const history: HistorySnapshot[] = [];
  const now = new Date();
  let netWorth = 45000; // Start a bit lower

  for (let i = 30; i >= 0; i--) {
    const date = new Date(now);
    date.setDate(date.getDate() - i);

    // Simulate realistic growth with some variation
    const dailyChange = (Math.random() - 0.4) * 200; // Slightly positive bias
    netWorth += dailyChange;

    history.push({
      snapshot_date: date.toISOString().split('T')[0],
      net_worth: Math.round(netWorth * 100) / 100,
      total_assets: Math.round((netWorth + 10800 + Math.random() * 500) * 100) / 100,
      total_liabilities: Math.round((10800 + Math.random() * 200) * 100) / 100,
    });
  }

  return history;
};

export default function NetWorthCard({ userId = 'default-user', onRefresh }: NetWorthCardProps) {
  const [breakdown, setBreakdown] = useState<NetWorthBreakdown | null>(null);
  const [history, setHistory] = useState<HistorySnapshot[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [showBreakdown, setShowBreakdown] = useState(false);

  const fetchNetWorth = async () => {
    setLoading(true);
    setError(null);

    try {
      const [currentRes, historyRes] = await Promise.all([
        fetch(`/api/net-worth?userId=${userId}`),
        fetch(`/api/net-worth/history?userId=${userId}&limit=30`)
      ]);

      const currentJson = await currentRes.json();
      const historyJson = await historyRes.json();

      if (currentJson.error) throw new Error(currentJson.error);

      // Use real data if available, otherwise fall back to demo
      setBreakdown(currentJson.netWorth ? currentJson : DEMO_BREAKDOWN);

      const historyData = historyJson.history || [];
      setHistory(historyData.length > 0 ? historyData : generateDemoHistory());
    } catch (err: any) {
      // Fall back to demo data on error
      setBreakdown(DEMO_BREAKDOWN);
      setHistory(generateDemoHistory());
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchNetWorth();
  }, [userId]);

  const formatCurrency = (value: number) => {
    const absValue = Math.abs(value);
    if (absValue >= 1000000) {
      return `$${(value / 1000000).toFixed(2)}M`;
    } else if (absValue >= 1000) {
      return `$${(value / 1000).toFixed(1)}k`;
    }
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 0,
      maximumFractionDigits: 0,
    }).format(value);
  };

  const formatFullCurrency = (value: number) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    }).format(value);
  };

  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
  };

  const handleRefresh = async () => {
    setLoading(true);
    try {
      await fetch('/api/net-worth/refresh', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId })
      });
      await fetchNetWorth();
      onRefresh?.();
    } catch (err) {
      console.error('Refresh failed:', err);
    }
    setLoading(false);
  };

  if (loading && !breakdown) {
    return <SkeletonNetWorth />;
  }

  if (!breakdown) return null;

  const isPositive = breakdown.netWorth >= 0;
  const netWorthColor = isPositive ? 'text-[#9C824A]' : 'text-[#EF0107]';

  // Calculate changes from history
  const firstSnapshot = history[0];
  const lastWeekSnapshot = history.find((_, i) => i === Math.max(0, history.length - 7));

  // 30-day change
  const change30d = firstSnapshot 
    ? breakdown.netWorth - firstSnapshot.net_worth 
    : 0;
  const changePercent30d = firstSnapshot && firstSnapshot.net_worth !== 0
    ? ((change30d / Math.abs(firstSnapshot.net_worth)) * 100)
    : 0;

  // 7-day change  
  const change7d = lastWeekSnapshot
    ? breakdown.netWorth - lastWeekSnapshot.net_worth
    : 0;
  const changePercent7d = lastWeekSnapshot && lastWeekSnapshot.net_worth !== 0
    ? ((change7d / Math.abs(lastWeekSnapshot.net_worth)) * 100)
    : 0;

  return (
    <div className="bg-zinc-900 rounded-lg p-6 border border-[#EF0107]/10 hover:border-[#EF0107]/20 transition card-hover">
      {/* Header */}
      <div className="flex items-center justify-between mb-4">
        <h3 className="font-semibold text-lg">Net Worth 🎯</h3>
        <button 
          onClick={handleRefresh}
          disabled={loading}
          className="text-zinc-400 hover:text-[#9C824A] text-sm transition disabled:opacity-50 focus-ring-arsenal"
          title="Refresh"
        >
          {loading ? <span className="arsenal-spinner w-4 h-4 inline-block" /> : '⟳'} Refresh
        </button>
      </div>

      {/* Big Number */}
      <div className="mb-4">
        <p className={`big-number ${netWorthColor}`}>
          {isPositive ? '' : '-'}{formatCurrency(Math.abs(breakdown.netWorth))}
        </p>
        <p className="text-zinc-400 text-sm mt-1">
          As of {breakdown.asOfDate}
        </p>
        {/* Arteta quote based on net worth */}
        <p className="text-zinc-500 text-xs italic mt-2">
          "{getNetWorthQuote(breakdown.netWorth)}"
        </p>
      </div>

      {/* Growth Stats Row */}
      {history.length > 1 && (
        <div className="grid grid-cols-2 gap-3 mb-4">
          <div className="bg-zinc-800/30 rounded-lg p-3 border border-zinc-700/50">
            <p className="text-zinc-500 text-xs uppercase tracking-wide mb-1">7-Day Change</p>
            <p className={`font-semibold ${change7d >= 0 ? 'text-[#9C824A]' : 'text-[#EF0107]'}`}>
              {change7d >= 0 ? '+' : ''}{formatCurrency(change7d)}
              <span className="text-xs ml-1 opacity-80">
                ({changePercent7d >= 0 ? '+' : ''}{changePercent7d.toFixed(1)}%)
              </span>
            </p>
          </div>
          <div className="bg-zinc-800/30 rounded-lg p-3 border border-zinc-700/50">
            <p className="text-zinc-500 text-xs uppercase tracking-wide mb-1">30-Day Change</p>
            <p className={`font-semibold ${change30d >= 0 ? 'text-[#9C824A]' : 'text-[#EF0107]'}`}>
              {change30d >= 0 ? '+' : ''}{formatCurrency(change30d)}
              <span className="text-xs ml-1 opacity-80">
                ({changePercent30d >= 0 ? '+' : ''}{changePercent30d.toFixed(1)}%)
              </span>
            </p>
          </div>
        </div>
      )}

      {/* Assets vs Liabilities Summary */}
      <div className="grid grid-cols-2 gap-4 mb-4">
        <div className="bg-zinc-800/50 rounded-lg p-3 border border-[#9C824A]/20">
          <p className="text-zinc-400 text-xs uppercase tracking-wide mb-1">Assets 🏆</p>
          <p className="text-[#9C824A] font-semibold text-lg stat-number">
            {formatCurrency(breakdown.assets.total)}
          </p>
        </div>
        <div className="bg-zinc-800/50 rounded-lg p-3 border border-[#EF0107]/20">
          <p className="text-zinc-400 text-xs uppercase tracking-wide mb-1">Liabilities</p>
          <p className="text-[#EF0107] font-semibold text-lg stat-number">
            {formatCurrency(breakdown.liabilities.total)}
          </p>
        </div>
      </div>

      {/* Expandable Breakdown */}
      <button
        onClick={() => setShowBreakdown(!showBreakdown)}
        className="text-zinc-400 hover:text-[#9C824A] text-sm mb-3 flex items-center gap-1 transition"
      >
        {showBreakdown ? '▼' : '▶'} View Breakdown
      </button>

      {showBreakdown && (
        <div className="border-t border-zinc-800 pt-3 space-y-3 mb-4 tab-content">
          {/* Assets Breakdown */}
          <div>
            <p className="text-xs text-zinc-500 uppercase tracking-wide mb-2">Assets Breakdown</p>
            <div className="space-y-1">
              <div className="flex justify-between text-sm">
                <span className="text-zinc-400">Cash (Checking/Savings)</span>
                <span className="text-[#9C824A] stat-number">{formatFullCurrency(breakdown.assets.cash)}</span>
              </div>
              <div className="flex justify-between text-sm">
                <span className="text-zinc-400">Investments</span>
                <span className="text-[#9C824A] stat-number">{formatFullCurrency(breakdown.assets.investments)}</span>
              </div>
            </div>
          </div>

          {/* Liabilities Breakdown */}
          <div>
            <p className="text-xs text-zinc-500 uppercase tracking-wide mb-2">Liabilities Breakdown</p>
            <div className="space-y-1">
              <div className="flex justify-between text-sm">
                <span className="text-zinc-400">Credit Cards</span>
                <span className="text-[#EF0107] stat-number">{formatFullCurrency(breakdown.liabilities.creditCards)}</span>
              </div>
              <div className="flex justify-between text-sm">
                <span className="text-zinc-400">Loans</span>
                <span className="text-[#EF0107] stat-number">{formatFullCurrency(breakdown.liabilities.loans)}</span>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Trend Chart */}
      {history.length > 1 && (
        <div className="border-t border-zinc-800 pt-4">
          <p className="text-xs text-zinc-500 uppercase tracking-wide mb-3">30-Day Trend</p>
          <ResponsiveContainer width="100%" height={120}>
            <LineChart data={history}>
              <CartesianGrid strokeDasharray="3 3" stroke="#3f3f46" vertical={false} />
              <XAxis 
                dataKey="snapshot_date" 
                tickFormatter={formatDate}
                stroke="#71717a"
                tick={{ fill: '#a1a1aa', fontSize: 10 }}
                axisLine={false}
                tickLine={false}
              />
              <YAxis 
                tickFormatter={(value) => `$${(value / 1000).toFixed(0)}k`}
                stroke="#71717a"
                tick={{ fill: '#a1a1aa', fontSize: 10 }}
                axisLine={false}
                tickLine={false}
                width={50}
              />
              <Tooltip
                contentStyle={{
                  backgroundColor: '#18181b',
                  border: '1px solid #EF0107',
                  borderRadius: '8px',
                  fontSize: '12px',
                }}
                formatter={(value: number | undefined) => value !== undefined ? [formatFullCurrency(value), 'Net Worth'] : ['--', 'Net Worth']}
                labelFormatter={formatDate}
              />
              <Line 
                type="monotone" 
                dataKey="net_worth" 
                stroke={isPositive ? '#9C824A' : '#EF0107'}
                strokeWidth={2}
                dot={false}
                activeDot={{ r: 4, fill: isPositive ? '#9C824A' : '#EF0107' }}
              />
            </LineChart>
          </ResponsiveContainer>
        </div>
      )}
    </div>
  );
}
